#include<bits/stdc++.h>
using namespace std;

#define MAX 1e17
long long f[100001], s[100001], n, m, st = 1 ;
bool v[100001];
struct node {
	int x;
	long long y;

};
struct cmp {
	bool operator()(node a, node b) {
		return a.y < b.y;
	}
};
vector<int> a[100001][2];
priority_queue<node, vector<node>, cmp> q;
void di(int x) {
    memset(v,false, sizeof(v));
    fill(s, s + 100001, -MAX); 
    s[st] = 0;
    q.push({st, 0});

	while (!q.empty()) {
		node now = q.top();
		q.pop();
		if (v[now.x]) continue;
		v[now.x] = true;
		for (int i = 0; i < a[now.x][0].size(); i++) {

			if (s[a[now.x][0][i]] < s[now.x] + a[now.x][1][i]) {
				s[a[now.x][0][i]] = a[now.x][1][i] + s[now.x];
				f[a[now.x][0][i]] = now.x;
				node temp;

				q.push({a[now.x][0][i], s[a[now.x][0][i]]});
			}

		}

	}
}
int main() {
	std::ios::sync_with_stdio(false);
	std::cin.tie(nullptr);
	cin >> n >> m;
	for (int i = 1; i <= n; i++) s[i] = -MAX;
	for (int i = 1; i <= m; i++) {
		int x, y, z;
		cin >> x >> y >> z;
		bool flag = 1;
		for (int j = 0; j < a[x][0].size(); j++) {

			if (a[x][0][j] == y) {
				flag = 0;
				a[x][1][j] = max(a[x][1][j], z);
                break;
			}

		}
		if (flag) {
			a[x][0].push_back(y);
			a[x][1].push_back(z);
		}
	}

	di(st);
	if (s[n] == -MAX) cout << -1;
	else cout << s[n];
	return 0;
}
